section.code:
{
  "$id": "langchain-chains/config",
  "type": "object",
  "required": ["pattern", "module_level", "exceptions_to_handle"],
  "additionalProperties": false,
  "properties": {
    "pattern": {"enum": ["sequential", "router", "map_reduce", "fallback"]},
    "module_level": {"type": "boolean"},
    "exceptions_to_handle": {
      "type": "array",
      "items": {"type": "string"},
      "minItems": 1,
      "description": "Class names of retryable exceptions; required when pattern=fallback."
    }
  }
}
